//! x86_64 cooperative context switch (M2): the naked `ctx_switch` primitive
//! plus the initial-stack fabricator that tb-hal's shared task layer
//! (`Task` / `task_create` / `yield_to` in `lib.rs`) builds on. ALL of M2's
//! x86_64 `unsafe`/asm lives HERE; the kernel crate stays
//! `#![forbid(unsafe_code)]` (KERNEL-FOUNDATION-SPEC §1).
//!
//! Verified facts QUOTED from primary sources, not invented:
//!   * Callee-saved set. System V AMD64 psABI §3.2.1, Figure 3.4 "Register
//!     Usage" (gitlab.com/x86-psABIs/x86-64-ABI, low-level-sys-info.tex):
//!     "Registers %rbp, %rbx and %r12 through %r15 ``belong'' to the calling
//!     function and the called function is required to preserve their
//!     values." A cooperative switch is call-shaped (`yield_to` is an
//!     ordinary `extern "C"` call), so it must preserve exactly
//!     {rbx, rbp, r12, r13, r14, r15} + rsp; every other GPR is
//!     caller-saved and already dead at the call site.
//!   * Stack alignment. psABI §3.2.2 "The Stack Frame": "The end of the
//!     input argument area shall be aligned on a 16 ... byte boundary", i.e.
//!     the stack is "16 ... byte aligned immediately before the call
//!     instruction is executed. Once control has been transferred to the
//!     function entry point, i.e. immediately after the return address has
//!     been pushed, %rsp points to the return address, and the value of
//!     (%rsp + 8) is a multiple of 16." The fabricated frame reproduces
//!     exactly that shape when the first switch `ret`s into the entry fn.
//!   * Switch model + initial-frame fabrication. xv6 (mit-pdos/xv6-public)
//!     swtch.S: "Save the current registers on the stack, creating a struct
//!     context, and save its address in *old. Switch stacks to new and pop
//!     previously-saved registers." proc.c `allocproc`: "Set up new context
//!     to start executing at forkret, which returns to trapret" — fabricate
//!     the new task's stack so the FIRST switch's `ret` lands in the entry
//!     function. Same callee-saved-on-stack technique as OSDev wiki
//!     "Context Switching" (Brendan) and phil-opp's kernel-threads material.
//!
//! No FP/SIMD state is saved or restored: the target is soft-float
//! (targets/x86_64-tabos-none.json: `"features": "-mmx,-sse,+soft-float"`),
//! so the compiler can never hold live state in x87/MMX/SSE registers.

use core::arch::naked_asm;
use core::mem::size_of;

/// Stack slot granularity: one machine word (8 bytes on x86_64).
const WORD: usize = size_of::<usize>();

/// How many callee-saved GPRs `ctx_switch` saves/restores: rbx, rbp,
/// r12, r13, r14, r15 (psABI Figure 3.4; rsp is handled separately as the
/// saved-context handle itself).
const CALLEE_SAVED: usize = 6;

/// Slots a fabricated initial frame occupies below the aligned stack top:
/// 6 callee-saved registers + the entry "return address" + the exit guard.
const INITIAL_FRAME_SLOTS: usize = CALLEE_SAVED + 2;

/// Refuse to fabricate a frame on a stack with fewer than this many `usize`
/// slots: the initial frame itself needs 9 (8 + worst-case alignment pad),
/// and anything close to that leaves no room for the entry fn's own frames.
/// (M2's kernel stacks are `[usize; 4096]` — 32 KiB — far above this floor.)
const MIN_STACK_SLOTS: usize = 32;

// ===========================================================================
// ctx_switch: the ONLY context-switch asm on x86_64.
// (a) PRE: called like a normal extern "C" fn from task A (rdi = where to
//     store A's SP, rsi = B's saved SP, a value previously produced by this
//     function or by `task_stack_init`). POST: callee-saved regs of A
//     {rbx,rbp,r12-r15} + A's resume RIP are parked on A's stack and
//     *prev_sp_save = A's SP; B's regs are reloaded from B's stack and `ret`
//     resumes B exactly where it called ctx_switch (or at its entry fn, on
//     B's first run). A resumes here, later, when someone switches back.
// (b) ABI: SysV extern "C" (args rdi/rsi); Intel syntax (Rust default). Saves
//     EXACTLY the psABI Fig. 3.4 callee-saved GPR set — "Registers %rbp,
//     %rbx and %r12 through %r15 belong to the calling function and the
//     called function is required to preserve their values" — everything
//     else is caller-saved, i.e. dead across this call. 6 pushes = 48 bytes
//     keeps rsp ≡ 8 (mod 16) throughout, matching psABI §3.2.2 "(%rsp + 8)
//     is a multiple of 16" at fn entry. Model: xv6 swtch.S ("Save the
//     current registers on the stack ... save its address in *old. Switch
//     stacks to new and pop previously-saved registers.").
// (c) Tested by: kernel M2 ping-pong — >=1000 strict A/B alternations with
//     live locals in callee-saved regs; scripts/run-x86_64.sh asserts the
//     "M2: context-switch OK" marker.
// ===========================================================================
/// Switch register context from the calling task to `next_sp`.
///
/// Saves the current task's callee-saved registers + return address on ITS
/// OWN stack, stores the resulting stack pointer to `*prev_sp_save` (the
/// caller's saved-context handle), installs `next_sp` as the stack pointer
/// and pops the next task's context, `ret`ing into its resume point.
///
/// # Safety
///
/// * `prev_sp_save` must be valid for an 8-byte write and not alias the
///   active region of either stack.
/// * `next_sp` must be a context handle produced by a previous `ctx_switch`
///   save or by [`task_stack_init`], on a stack that is still alive
///   and not currently executing on any CPU.
#[unsafe(naked)]
pub unsafe extern "C" fn ctx_switch(prev_sp_save: *mut usize, next_sp: usize) {
    naked_asm!(
        // Save current task's callee-saved context on its own stack.
        "push rbx",
        "push rbp",
        "push r12",
        "push r13",
        "push r14",
        "push r15",
        // Publish the old task's saved-SP handle, then switch stacks.
        "mov [rdi], rsp", // *prev_sp_save = current SP
        "mov rsp, rsi",   // SP = next task's saved SP
        // Restore the next task's callee-saved context (reverse order).
        "pop r15",
        "pop r14",
        "pop r13",
        "pop r12",
        "pop rbp",
        "pop rbx",
        // Return into the next task: pops its saved RIP — either where it
        // last called ctx_switch, or the fabricated entry slot (first run).
        "ret",
    )
}

/// Fabricate the initial saved context for a NEW task on `stack`, so that
/// the first [`ctx_switch`] INTO it pops six zeroed callee-saved registers
/// and `ret`s into `entry` (xv6 `allocproc` / OSDev-Brendan technique).
///
/// Frame layout built at the 16-byte-aligned logical top of `stack`
/// (addresses descend; `top` is aligned DOWN from the slice end):
///
/// ```text
///   top      ─ 16-byte aligned ─ (0..1 pad slot may exist above, unused)
///   top -  8: task_exit_guard   ← entry's caller, if entry ever returns
///   top - 16: entry             ← popped by ctx_switch's final `ret`
///   top - 24: 0 (rbx)   ┐
///   top - 32: 0 (rbp)   │ popped rbx-last by ctx_switch
///   top - 40: 0 (r12)   │ (push order rbx..r15 ⇒ r15 at the
///   top - 48: 0 (r13)   │  lowest address, rbx at the highest)
///   top - 56: 0 (r14)   │
///   top - 64: 0 (r15)   ┘ ← returned initial SP (saved-context handle)
/// ```
///
/// At entry to `entry`, rsp = top - 8, so (rsp + 8) = top ≡ 0 (mod 16) —
/// exactly the psABI §3.2.2 post-`call` shape the compiler assumes. The
/// returned handle (top - 64) also stays 16-aligned, since the 6 register
/// slots + 2 address slots total 64 bytes.
///
/// Pure safe Rust: only slice indexing + integer math; the resulting handle
/// is consumed by `ctx_switch`'s asm. Panics if `stack` has fewer than
/// [`MIN_STACK_SLOTS`] slots.
pub fn task_stack_init(stack: &mut [usize], entry: fn()) -> usize {
    assert!(
        stack.len() >= MIN_STACK_SLOTS,
        "task stack too small to fabricate an initial context"
    );

    let base = stack.as_mut_ptr() as usize;
    let limit = base + stack.len() * WORD;
    // Logical stack top: slice end aligned DOWN to 16 bytes (`[usize]` only
    // guarantees 8-byte alignment, so up to one slot above `top` is unused).
    let top = limit & !0xF;

    // Address -> index into `stack`; in-bounds because top - 64 >= base for
    // any slice of >= 9 slots (and MIN_STACK_SLOTS is far above that).
    let slot = |addr: usize| (addr - base) / WORD;

    // (fn-item -> raw-ptr -> usize: the two-step cast rustc requires.)
    stack[slot(top - WORD)] = task_exit_guard as *const () as usize; // guard
    stack[slot(top - 2 * WORD)] = entry as usize; // `ret` target, first switch
    for i in 0..CALLEE_SAVED {
        stack[slot(top - (3 + i) * WORD)] = 0; // rbx, rbp, r12, r13, r14, r15
    }

    top - INITIAL_FRAME_SLOTS * WORD // the initial saved-SP handle
}

// ===========================================================================
// task_exit_guard: landing pad if a task's entry fn ever returns.
// (a) PRE: a task's entry fn executed `ret` with rsp back at its fabricated
//     entry shape (rsp = top - 8), popping this guard's address; rsp = top,
//     which is 16-aligned — NOT the (%rsp + 8) % 16 == 0 shape a normal Rust
//     fn entered via `call` may assume. POST: never returns; realigns, then
//     calls the diverging Rust reporter, which halts the core.
// (b) ABI: naked, so no prologue assumes anything about the stack. `and
//     rsp, -16` forces 16-alignment, and the `call` then pushes 8 so
//     `task_exit_fail` gets the exact psABI §3.2.2 "(%rsp + 8) is a multiple
//     of 16" entry shape. Intel syntax (Rust default).
// (c) Tested by: construction only — M2's ping-pong tasks loop forever and
//     never return; this guard turns the "task returned" bug class into a
//     deterministic serial message + halt instead of a wild jump.
// ===========================================================================
/// Diverging landing pad placed above each fabricated entry frame; reached
/// only if a task's entry function returns (which M2 tasks never do).
#[unsafe(naked)]
extern "C" fn task_exit_guard() -> ! {
    naked_asm!(
        "and rsp, -16",  // restore the alignment invariant for the call below
        "call {fail}",   // diverges (prints + halts); never comes back
        "2: jmp 2b",     // belt-and-braces: park if it somehow did
        fail = sym task_exit_fail,
    )
}

/// Report a returned task entry fn over serial, then park the core forever.
/// Called only from `task_exit_guard`, after it has realigned the stack.
extern "C" fn task_exit_fail() -> ! {
    crate::serial_write_str("M2: FAIL task entry fn returned\n");
    super::halt()
}

//! x86_64 architecture backend for `tb-hal`.
//!
//! Exposes the safe primitives that `tb-hal`'s public API
//! (`serial_init`, `serial_write_byte`, `serial_write_str`, `halt`,
//! `install_traps`, `breakpoint`) delegates to via `arch::mod`. ALL x86_64
//! `unsafe` and assembly is confined to this `arch::x86_64` subtree
//! (KERNEL-FOUNDATION-SPEC §1); every other crate is `#![forbid(unsafe_code)]`.
//!
//! M0 boot path is PVH: `boot` emits the `XEN_ELFNOTE_PHYS32_ENTRY` note and
//! the (bootstrap-only) 32->64 trampoline; `serial` is the 16550 COM1 driver.
//! M1 adds CPU trap handling: `gdt` installs a permanent flat 64-bit GDT + TSS
//! (IST stacks), `idt` installs the 256-gate IDT, and `trap` holds the entry
//! thunks + the extern "C" handler that dispatches into safe Rust policy.
//! M2 adds the cooperative context switch: `sched` holds the naked
//! `ctx_switch` (saves/restores ONLY the psABI Fig. 3.4 callee-saved set
//! {rbx, rbp, r12-r15} + rsp, callee-saved-on-stack model) and the
//! initial-frame fabricator that tb-hal's shared `Task`/`task_create`/
//! `yield_to` layer builds on.

// `_start`, the PVH note and the 32->64 trampoline live here. The module is
// pulled into the final link because the linker script's `ENTRY(_start)`
// turns `_start` into a needed symbol, forcing extraction from the rlib.
pub mod boot;
pub mod serial;

// M1 trap stack: GDT/TSS, IDT, and the trap entry/dispatch asm + handler.
pub mod gdt;
pub mod idt;
pub mod trap;

// M2 cooperative switch: naked ctx_switch + new-task stack fabrication.
pub mod sched;

pub use serial::{serial_init, serial_write_byte};

// `breakpoint()` is re-exported as part of tb-hal's public trap surface; the
// `int3` lives in `trap.rs`. `set_trap_hook`/`TrapInfo`/`TrapKind`/`TrapAction`
// and the `dispatch_trap` glue live at the crate root (`lib.rs`).
pub use trap::breakpoint;

// M2: the arch-internal primitives consumed by the shared task layer in
// `lib.rs` (`Task`, `task_create`, `yield_to`). Per-arch contract:
//   * `unsafe extern "C" fn ctx_switch(prev_sp_save: *mut usize, next_sp: usize)`
//     — save the CURRENT task's callee-saved context on its own stack, store
//     the resulting SP to `*prev_sp_save`, adopt `next_sp` and resume the
//     next task (callee-saved-on-stack model, xv6 swtch.S shape).
//   * `fn task_stack_init(stack: &mut [usize], entry: fn()) -> usize`
//     — fabricate a brand-new task's initial frame on `stack` so the FIRST
//     switch into it `ret`s into `entry`; returns the initial saved-SP handle
//     that `task_create` records for the first `yield_to`.
// (Same names + signatures as the aarch64 arm, so `arch/mod.rs` re-exports
// one uniform contract to `lib.rs`.)
pub use sched::{ctx_switch, task_stack_init};

use core::sync::atomic::{AtomicBool, Ordering};

/// Guards `install_traps()` so the permanent GDT/TSS/IDT are only built once
/// per vCPU even if it is called more than once.
static TRAPS_INSTALLED: AtomicBool = AtomicBool::new(false);

/// Install real CPU exception/interrupt handling: load the permanent GDT+TSS
/// (with IST stacks) FIRST, then the IDT (whose #DF/NMI/#MC gates reference
/// those IST stacks). Idempotent; called once from `rust_main` via
/// `tb_hal::install_traps()`.
pub fn install_traps() {
    if TRAPS_INSTALLED.swap(true, Ordering::SeqCst) {
        return;
    }
    // Order matters: the IDT's IST indices select TSS stacks the GDT installs.
    gdt::init();
    idt::init();
}

/// Halt the calling (single) vCPU forever.
///
/// Masks interrupts and parks the core in a `hlt` loop. Used as the M0
/// Definition-of-Done terminator after the marker is printed, as the fatal
/// (`TrapAction::Halt`) trap terminator, and as the `#[panic_handler]`
/// fallback in the kernel crate. Never returns.
#[inline]
pub fn halt() -> ! {
    loop {
        // (a) PRE: any CPU state. POST: interrupts masked, core parked; the
        //     function never observably returns (the surrounding loop re-arms
        //     `hlt` after any spurious NMI/SMI wake).
        // (b) ABI: no operands; clobbers nothing; nomem/nostack. `hlt` clears
        //     no caller state; `cli` only affects IF.
        // (c) Tested by: scripts/run-x86_64.sh (kernel halts after emitting
        //     its markers; the runner times out and scrapes COM1).
        unsafe {
            core::arch::asm!("cli", "hlt", options(nomem, nostack, preserves_flags));
        }
    }
}

//! aarch64 cooperative context switch (M2): `ctx_switch` + the initial frame.
//!
//! This is the aarch64 half of milestone **M2** ("cooperative context
//! switch"). It provides the two arch primitives the safe `tb-hal` task API
//! in `lib.rs` (`Task` / `task_create` / `yield_to`) delegates to:
//!
//!  * [`ctx_switch`] — the raw switch (`global_asm!` below): push the current
//!    task's callee-saved registers onto its own stack, publish the resulting
//!    SP through `prev_sp_save`, adopt `next_sp`, pop the next task's
//!    callee-saved registers, and `ret` into it.
//!  * [`task_stack_init`] — fabricate the INITIAL context frame on a
//!    brand-new task's stack so the very first switch into it "returns" into
//!    `entry`. Fabrication is pure safe Rust (slice writes); only the switch
//!    itself is assembly.
//!
//! Saved-context model ("callee-saved-on-stack"): `ctx_switch` is an ordinary
//! `extern "C"` call, so at every call site the compiler has already spilled
//! or given up every caller-saved value; only the callee-saved set survives a
//! call in registers, so that set — and nothing else — is what the switch
//! must carry from one task to the other. The saved SP doubles as the whole
//! context handle (same model as the x86_64 side in `arch/x86_64/sched.rs`).
//!
//! Verified facts (obey exactly):
//!  * AAPCS64 callee-saved set: **r19-r29 and SP**, with r29 = FP and
//!    r30 = LR holding the return address. Procedure Call Standard for the
//!    Arm 64-bit Architecture (github.com/ARM-software/abi-aa,
//!    `aapcs64/aapcs64.rst`), §6.1.1 "General-purpose registers": "r19…r28 —
//!    Callee-saved registers", and: "r19-r29 and SP are Callee-saved. All 64
//!    bits of each value stored in r19-r29 are Callee-saved." The resume
//!    address rides in x30/LR, so the frame stores **x19..x28 + x29(FP) +
//!    x30(LR)** = 12 registers; SP is the handle, not a slot.
//!  * Stack alignment, AAPCS64 "Universal stack constraints" (§6.4.5): "SP
//!    mod 16 = 0. The stack must be quad-word aligned." The 0x60-byte frame
//!    is a multiple of 16 and the fabricated initial SP is aligned down to
//!    16, so SP is quad-word aligned at every instruction of the switch and
//!    at task entry.
//!  * Frame-record chain termination (AAPCS64 §6.4.6 "The Frame Pointer"):
//!    "The end of the frame record chain is indicated by the address zero in
//!    the address for the previous frame." — why the fabricated x29 slot is 0.
//!  * Cross-check, Linux v6.6 `arch/arm64/kernel/entry.S` `cpu_switch_to`
//!    (lines 822-847): stp/ldp of exactly `x19..x28`, `x29 + sp`, `lr`
//!    ("store callee-saved registers"), then `ret` — same register set, same
//!    LR-carries-the-resume-address model (Linux parks the frame in
//!    `task_struct.thread.cpu_context`; we park it on the task stack).
//!  * Initial-frame fabrication technique: OSDev Wiki, "Brendan's
//!    Multi-tasking Tutorial": "put values on the new kernel stack to match
//!    the values that your 'switch_to_task(task)' function expects to pop off
//!    the stack after switching to the task ... the values on the new kernel
//!    stack will include a 'return EIP' (the address that the
//!    'switch_to_task(task)' function will return to)". Same technique in
//!    Linux v6.6 `arch/arm64/kernel/process.c` `copy_thread`:
//!    `p->thread.cpu_context.pc = (unsigned long)ret_from_fork;` — a new
//!    task's first switch "returns" into a fabricated entry point.
//!  * No FP/SIMD state is saved: `targets/aarch64-tabos-none.json` is
//!    `abi: softfloat` with `-fp-armv8,-neon`, so the V registers carry no
//!    live values (same reasoning as the M1 `TrapFrame` in `vectors.rs`).
//!
//! Saved-context frame layout (byte offsets from the saved SP; 0x60 = 96 B,
//! shared verbatim between the assembly and [`task_stack_init`]):
//!
//! ```text
//! [sp+0x00] x19   [sp+0x08] x20   [sp+0x10] x21   [sp+0x18] x22
//! [sp+0x20] x23   [sp+0x28] x24   [sp+0x30] x25   [sp+0x38] x26
//! [sp+0x40] x27   [sp+0x48] x28   [sp+0x50] x29   [sp+0x58] x30 <- resume PC
//! ```

use core::arch::global_asm;
use core::mem::size_of;

/// `usize` slots in one saved-context frame: x19..x28 (10) + x29/FP + x30/LR.
const CTX_FRAME_SLOTS: usize = 12;

/// Frame size in bytes (0x60). A multiple of 16, so pushing/popping a frame
/// preserves the AAPCS64 "SP mod 16 = 0" universal stack constraint.
const CTX_FRAME_BYTES: usize = CTX_FRAME_SLOTS * size_of::<usize>();

/// Frame slot index of x30/LR — the address `ctx_switch` `ret`s to. For a
/// fabricated frame this slot holds `entry`; offset 0x58, matching the asm.
const CTX_SLOT_LR: usize = CTX_FRAME_SLOTS - 1;

/// Smallest stack (in `usize` slots) [`task_stack_init`] accepts: one frame
/// (12) + worst-case 16-byte top alignment loss (1) + a little headroom. The
/// kernel's real M2 stacks are 4096 slots; this only rejects absurd inputs.
const MIN_STACK_SLOTS: usize = 32;

// Compile-time locks on the layout the assembly below assumes.
const _: () = assert!(CTX_FRAME_BYTES == 0x60 && CTX_FRAME_BYTES % 16 == 0);
const _: () = assert!(CTX_SLOT_LR * size_of::<usize>() == 0x58);

// -- ctx_switch ---------------------------------------------------------------
// (a) PRE : extern "C" call with x0 = prev_sp_save (*mut usize save slot for
//           the CURRENT task) and x1 = next_sp (a handle from task_stack_init
//           or from a previous save through *prev_sp_save); SP 16-aligned
//           (AAPCS64 invariant holds on every call). POST: the current task's
//           x19..x30 sit in a 0x60-byte frame on its own stack with
//           *prev_sp_save = that frame's SP; execution continues in the next
//           task at its saved x30 with x19..x29 + SP restored.
// (b) ABI : AAPCS64. Beyond the callee-saved set it deliberately reloads, it
//           clobbers only x2 (caller-saved); memory touched: [sp-0x60, sp) of
//           the old stack, [x1, x1+0x60) of the new one, the 8-byte store to
//           *x0. SP stays 16-aligned at every step (0x60 % 16 == 0; AAPCS64
//           "SP mod 16 = 0"). Register set per AAPCS64 §6.1.1 / Linux v6.6
//           cpu_switch_to (see module note).
// (c) TEST: scripts/run-aarch64.sh — the M2 ping-pong (>=1000 strict A/B
//           round trips with callee-saved canaries) prints
//           "M2: context-switch OK".
global_asm!(
    r#"
    .section .text._sched, "ax"
    .balign 4
    .globl ctx_switch
ctx_switch:
    // Push the AAPCS64 callee-saved set onto the CURRENT task's stack.
    sub  sp, sp, #0x60            // 12 slots; 0x60 % 16 == 0 keeps SP aligned
    stp  x19, x20, [sp, #0x00]
    stp  x21, x22, [sp, #0x10]
    stp  x23, x24, [sp, #0x20]
    stp  x25, x26, [sp, #0x30]
    stp  x27, x28, [sp, #0x40]
    stp  x29, x30, [sp, #0x50]    // FP + LR; LR is this task's resume address

    // Publish the frame: the saved SP itself is the whole context handle.
    mov  x2, sp
    str  x2, [x0]                 // *prev_sp_save = SP

    // Adopt the next task's saved SP and pop ITS callee-saved set.
    mov  sp, x1
    ldp  x19, x20, [sp, #0x00]
    ldp  x21, x22, [sp, #0x10]
    ldp  x23, x24, [sp, #0x20]
    ldp  x25, x26, [sp, #0x30]
    ldp  x27, x28, [sp, #0x40]
    ldp  x29, x30, [sp, #0x50]    // x30 = resume PC (or the fabricated entry)
    add  sp, sp, #0x60
    ret                           // branch to x30: continue the next task
"#
);

extern "C" {
    /// Cooperative context switch — the raw M2 primitive (assembly above).
    ///
    /// Saves the current task's AAPCS64 callee-saved registers (x19..x28,
    /// x29/FP, x30/LR) in a 0x60-byte frame on its own stack, stores the
    /// resulting SP to `*prev_sp_save`, switches SP to `next_sp`, restores the
    /// next task's frame, and returns into it (at its saved x30). For a frame
    /// fabricated by [`task_stack_init`] that "return" is the first entry into
    /// the task's `entry` function.
    ///
    /// # Safety
    ///
    /// * `prev_sp_save` must be valid, 8-aligned, and writable; it receives
    ///   the only handle through which the current task can ever be resumed.
    /// * `next_sp` must be a live context handle: the value produced by
    ///   [`task_stack_init`], or one stored through `prev_sp_save` by an
    ///   earlier `ctx_switch`, whose backing stack is still alive ('static in
    ///   M2) and which has not already been consumed by a switch.
    /// * Cooperative single-core use only — never call from a trap handler.
    pub fn ctx_switch(prev_sp_save: *mut usize, next_sp: usize);
}

// -- task_stack_init ----------------------------------------------------------
// (a) PRE : `stack` is the new task's (caller-owned, in M2 'static) stack
//           array, >= MIN_STACK_SLOTS slots; `entry` is the task body. POST:
//           the top of `stack` (aligned down to 16) holds one fabricated
//           0x60-byte frame — x19..x28 = 0, x29 = 0 (frame-record chain
//           terminator), x30 = entry — and the returned value is the frame's
//           SP, ready to be passed to `ctx_switch` as `next_sp` exactly once.
// (b) ABI : pure safe Rust; no asm, no unsafe — plain slice writes. The frame
//           bytes/offsets mirror the `ctx_switch` assembly via the shared
//           CTX_* constants. Returned SP is 16-aligned; after the first
//           switch pops the frame, `entry` starts with SP = aligned stack
//           top (AAPCS64 "SP mod 16 = 0" holds) and FP = 0.
// (c) TEST: scripts/run-aarch64.sh — task B of the M2 ping-pong enters
//           through exactly this fabricated frame.
/// Fabricate the initial saved context for a new task on `stack`.
///
/// Builds, at the (16-byte aligned-down) top of `stack`, the exact 0x60-byte
/// frame [`ctx_switch`] expects to pop: x19..x28 zeroed, x29/FP zeroed (the
/// AAPCS64 frame-record chain ends at address zero), and x30/LR = `entry`, so
/// the first switch into the returned handle pops zeros and `ret`s straight
/// into `entry` (OSDev "Brendan's Multi-tasking Tutorial" technique; Linux
/// `copy_thread` does the same with `cpu_context.pc = ret_from_fork`).
///
/// Returns the fabricated SP — the context handle to pass to [`ctx_switch`]
/// (via the safe `yield_to`) as `next_sp` for the task's FIRST activation.
///
/// `entry` must never return: there is no caller frame beneath it. In M2 every
/// task either yields forever or ends in `halt()`.
///
/// # Panics
///
/// Panics if `stack` has fewer than `MIN_STACK_SLOTS` (32) slots.
pub fn task_stack_init(stack: &mut [usize], entry: fn()) -> usize {
    assert!(
        stack.len() >= MIN_STACK_SLOTS,
        "task stack too small for an initial context frame"
    );

    // Align the stack TOP down to 16 bytes (AAPCS64 universal stack
    // constraint: "SP mod 16 = 0"). A `[usize]` is only guaranteed 8-aligned,
    // so at most one 8-byte slot is sacrificed.
    let base = stack.as_ptr() as usize;
    let top = (base + stack.len() * size_of::<usize>()) & !0xF;
    let frame_sp = top - CTX_FRAME_BYTES;

    // Both `frame_sp` and `base` are 8-aligned, so the slot index is exact;
    // `frame_sp + 0x60 == top <= base + len*8` keeps the range in bounds.
    let first = (frame_sp - base) / size_of::<usize>();

    // x19..x28 = 0 and x29/FP = 0 (frame-record chain terminator) ...
    for slot in &mut stack[first..first + CTX_FRAME_SLOTS] {
        *slot = 0;
    }
    // ... and x30/LR = entry: what the first `ctx_switch` will `ret` into.
    stack[first + CTX_SLOT_LR] = entry as usize;

    frame_sp
}

//! aarch64 backend for the `tb-hal` foundation crate.
//!
//! One of the two `#[cfg(target_arch)]` arms re-exported by `arch/mod.rs`. It
//! exposes the aarch64 primitives the safe `tb-hal` public API (`lib.rs`)
//! delegates to: [`serial_init`], [`serial_write_byte`], [`halt`] (M0), the
//! M1 trap surface [`install_traps`] and [`breakpoint`], and the M2
//! cooperative-scheduling primitives [`ctx_switch`] and [`task_stack_init`]
//! (backing `lib.rs`'s safe `Task` / `task_create` / `yield_to`).
//! (`serial_write_str` is composed in `lib.rs` from `serial_write_byte`, so it
//! is arch-independent.)
//!
//! Boot contract for the M0/M1 QEMU `virt` path (verified facts,
//! KERNEL-FOUNDATION-SPEC SS2): the vCPU enters `_start` at **EL1h, MMU OFF,
//! DAIF masked**, with **x0 = FDT/DTB pointer** (AAPCS64 arg0 already).
//! `boot.rs` owns that entry; `serial.rs` owns the PL011 UART; `vectors.rs`
//! owns the `VBAR_EL1` table; `trap.rs` owns the Rust trap dispatch;
//! `sched.rs` owns the M2 context switch (callee-saved x19..x30 + SP) and the
//! new-task initial-frame fabrication (x30 = entry).

mod boot; // _start; arms VBAR_EL1; pure side-effect (`global_asm!`) module.
mod sched; // M2: ctx_switch (x19..x30 + SP) + initial-frame fabrication.
mod serial; // PL011 @ 0x0900_0000 (QEMU `virt` UART0).
mod trap; // Rust trap dispatch + breakpoint(); the only raw-frame deref.
mod vectors; // VBAR_EL1 table + entry/exit stubs; pure `global_asm!` module.

pub use sched::{ctx_switch, task_stack_init};
pub use serial::{serial_init, serial_write_byte};
pub use trap::breakpoint;

// -- install_traps() --------------------------------------------------------
// (a) PRE : called once from rust_main, after serial_init, at EL1h. POST:
//           VBAR_EL1 == &__exception_vectors (the 2 KiB-aligned table in
//           vectors.rs) and an `isb` has made the new vector base
//           architecturally visible. Idempotent: `_start` already pre-armed the
//           very same table, so a second call just re-writes the same value.
// (b) ABI : clobbers one scratch x-register; touches no memory/stack; takes no
//           args. Arm ARM D19.2 requires a context-synchronisation event after
//           writing VBAR_EL1 before relying on it -- the `isb` provides it.
// (c) TEST: scripts/run-aarch64.sh -- after install, breakpoint() is caught,
//           the hook resumes, and the kernel prints "M1: traps OK".
/// Install the EL1 exception vectors (`VBAR_EL1`). Idempotent; call once.
pub fn install_traps() {
    // SAFETY: writing VBAR_EL1 is legal at EL1 and merely (re)selects our own
    // 2 KiB-aligned vector table (`vectors.rs`); `adrp/add :lo12:` form its
    // address with no memory access, and `isb` synchronises the change.
    unsafe {
        core::arch::asm!(
            "adrp {t}, __exception_vectors",
            "add  {t}, {t}, :lo12:__exception_vectors",
            "msr  vbar_el1, {t}",
            "isb",
            t = out(reg) _,
            options(nomem, nostack, preserves_flags),
        );
    }
}

// -- halt() -----------------------------------------------------------------
// (a) PRE : any state; called on the M0/M1 happy path after the marker is
//           flushed, from the kernel #[panic_handler], and from the trap
//           handler's fatal (Halt) path. POST: never returns -- the vCPU is
//           parked in a low-power wait, re-parking on any wake event.
// (b) ABI : `wfi` clobbers nothing, touches no memory/stack, preserves NZCV.
// (c) TEST: scripts/run-aarch64.sh -- the kernel reaches here after printing
//           "M1: traps OK"; the runner times out and asserts the marker.
/// Halt the current vCPU forever (low-power wait loop).
pub fn halt() -> ! {
    loop {
        // SAFETY: `wfi` is an unprivileged hint with no memory or stack
        // effects; it is always legal at EL1 and merely suspends the core
        // until a wake event, after which we loop and re-park.
        unsafe {
            core::arch::asm!("wfi", options(nomem, nostack, preserves_flags));
        }
    }
}

//! `tb-hal` — TABOS Hardware Abstraction Layer (M0 serial + M1 traps + M2 tasks).
//!
//! This crate is the single place where `unsafe` and assembly are allowed in
//! TABOS (framekernel rule, KERNEL-FOUNDATION-SPEC.md §1). The raw pokes live in
//! the per-arch submodules under `arch/`; THIS file is a thin, mostly-safe
//! facade exposing the symbols the `kernel` crate is allowed to call:
//!
//! M0 serial + park:
//!   * [`serial_init`], [`serial_write_byte`], [`serial_write_str`], [`halt`]
//!
//! M1 traps:
//!   * [`install_traps`]  — load the permanent GDT+TSS+IDT (x86_64) / set
//!     `VBAR_EL1` (aarch64). Idempotent, called once from `rust_main`.
//!   * [`breakpoint`]     — execute a software breakpoint (`int3` / `brk #0`).
//!   * [`set_trap_hook`]  — register the safe dispatch policy hook.
//!   * [`TrapInfo`] / [`TrapKind`] / [`TrapAction`] — the safe trap-dispatch ABI.
//!
//! M2 cooperative tasks (this milestone):
//!   * [`Task`], [`task_create`], [`yield_to`] — voluntary (cooperative)
//!     context switch between kernel tasks. Only the ABI callee-saved
//!     registers plus the stack pointer are switched; the saved SP is the
//!     ENTIRE per-task context handle (verified ABI facts in the M2 section
//!     below).
//!   * [`TaskStack`] — one-shot-takeable static stack cell, so the
//!     `#![forbid(unsafe_code)]` kernel crate can OWN its static stack arrays
//!     (tb-hal allocates nothing) and still mint the unique `&'static mut`
//!     that [`task_create`] requires.
//!   * [`current_task`] — handle of the task executing right now (slot 0 is
//!     the bootstrap context that entered `rust_main`).
//!
//! POLICY lives in safe Rust: tb-hal's per-arch assembly marshals a raw
//! `TrapFrame`, an `extern "C"` handler in tb-hal (the ONLY place that derefs
//! the raw frame, `unsafe`) builds a safe [`TrapInfo`] and calls the registered
//! hook via [`dispatch_trap`]. The default hook returns [`TrapAction::Halt`].

#![no_std]
#![deny(missing_docs)]

use core::cell::UnsafeCell;
use core::sync::atomic::{AtomicBool, AtomicUsize, Ordering};

mod arch;

/// Initialise the early serial console for the current architecture.
///
/// * x86_64: legacy 16550 UART, COM1 @ I/O port `0x3F8`.
/// * aarch64: PL011 UART0 @ MMIO `0x0900_0000` (QEMU `virt` first-light).
///
/// Must be called once before any [`serial_write_byte`] / [`serial_write_str`].
pub fn serial_init() {
    arch::serial_init();
}

/// Write a single byte to the early serial console, blocking until the UART can
/// accept it.
pub fn serial_write_byte(b: u8) {
    arch::serial_write_byte(b);
}

/// Write a string to the early serial console, byte by byte (blocking).
///
/// Pure safe Rust: this is just a loop over [`serial_write_byte`]; it performs
/// no `unsafe` itself.
pub fn serial_write_str(s: &str) {
    for &b in s.as_bytes() {
        arch::serial_write_byte(b);
    }
}

/// Halt the (single) vCPU forever. Never returns.
///
/// * x86_64: masked `cli; hlt` spin.
/// * aarch64: `wfi` spin with interrupts masked.
pub fn halt() -> ! {
    arch::halt()
}

// ===========================================================================
// M1: trap installation + safe dispatch ABI
// ===========================================================================

/// Install real CPU exception/interrupt handling for the current architecture.
///
/// * x86_64: build and load a PERMANENT flat 64-bit GDT (null, ring0 code,
///   ring0 data, 64-bit TSS), reload `CS`/data segments, `ltr` the TSS, then
///   load a 256-entry IDT of 64-bit interrupt gates. `#DF`/NMI/`#MC` are routed
///   through TSS IST stacks.
/// * aarch64: point `VBAR_EL1` at the 2 KiB-aligned, 16×128-byte vector table.
///
/// Idempotent: safe to call more than once (each call rebuilds the descriptor
/// tables from scratch). Call once early from `rust_main`, before [`breakpoint`].
pub fn install_traps() {
    arch::install_traps();
}

/// Execute a software breakpoint trap on the current architecture.
///
/// * x86_64: `int3` (`#BP`, vector 3) — a TRAP whose CPU-saved `RIP` already
///   points PAST the instruction, so it resumes automatically on
///   [`TrapAction::Resume`].
/// * aarch64: `brk #0` — a SYNCHRONOUS exception (`ESR_EL1.EC = 0x3C`) whose
///   `ELR_EL1` points AT the instruction; the trap entry advances `ELR_EL1` by
///   4 on [`TrapAction::Resume`].
pub fn breakpoint() {
    arch::breakpoint();
}

/// The architecture-neutral classification of a trap, derived in the per-arch
/// `extern "C"` handler from the raw cause (vector + error code on x86_64,
/// `ESR_EL1.EC` on aarch64).
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum TrapKind {
    /// Software breakpoint: x86 `#BP` (vector 3) / aarch64 `brk` (EC `0x3C`).
    Breakpoint,
    /// Page / data fault: x86 `#PF` (vector 14) / aarch64 data abort
    /// (EC `0x24`/`0x25`). [`TrapInfo::fault_addr`] holds the faulting address.
    PageFault,
    /// Undefined / invalid instruction: x86 `#UD` (vector 6) / aarch64 Unknown
    /// (EC `0x00`).
    Undefined,
    /// Any other trap not specially classified above.
    Other,
}

/// What the dispatch hook asks tb-hal to do after a trap is handled.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum TrapAction {
    /// Return from the trap entry so execution continues past the trapping
    /// instruction (x86: `iretq`; aarch64: `eret`, advancing `ELR_EL1` by 4 for
    /// the at-instruction synchronous breakpoint).
    Resume,
    /// Do not return; park the vCPU forever. Used for fatal faults and as the
    /// default policy when no hook is registered.
    Halt,
}

/// A safe, fully-owned description of a trap, handed to the dispatch hook.
///
/// Built inside tb-hal's per-arch handler from the raw `TrapFrame`; it borrows
/// nothing from the raw frame, so the hook (in the otherwise-`forbid(unsafe)`
/// kernel crate) can read it freely.
#[derive(Clone, Copy, Debug)]
pub struct TrapInfo {
    /// The architecture-neutral kind of this trap.
    pub kind: TrapKind,
    /// Raw cause word. x86_64: `(vector << 32) | (error_code & 0xFFFF_FFFF)`.
    /// aarch64: the full `ESR_EL1` value (EC = bits `[31:26]`).
    pub cause: u64,
    /// Faulting address for memory faults (x86 `CR2` for `#PF`; aarch64
    /// `FAR_EL1` for a data abort), otherwise `0`.
    pub fault_addr: u64,
    /// The trapping instruction pointer (x86 saved `RIP`; aarch64 `ELR_EL1`).
    pub pc: u64,
}

/// Storage for the registered trap hook: a `fn(&TrapInfo) -> TrapAction`
/// reinterpreted as `usize`. `0` means "no hook registered → use the default
/// halt policy". `AtomicUsize` because tb-hal is `no_std` with no locks; the
/// pointer is written once at boot and read on every trap.
static TRAP_HOOK: AtomicUsize = AtomicUsize::new(0);

/// The default policy when no hook has been registered: always halt.
fn default_trap_hook(_info: &TrapInfo) -> TrapAction {
    TrapAction::Halt
}

/// Register the safe trap-dispatch policy hook.
///
/// The hook is a plain function pointer `fn(&TrapInfo) -> TrapAction`; it lives
/// in safe Rust (e.g. the kernel crate under `#![forbid(unsafe_code)]`) and
/// decides per-trap whether to [`TrapAction::Resume`] or [`TrapAction::Halt`].
pub fn set_trap_hook(hook: fn(&TrapInfo) -> TrapAction) {
    TRAP_HOOK.store(hook as usize, Ordering::Release);
}

/// Dispatch a trap to the registered hook (or the default halt policy).
///
/// Called by each per-arch `extern "C"` handler with a [`TrapInfo`] it built
/// from the raw frame. This is the safe boundary between the raw-frame deref
/// (per-arch, `unsafe`) and the policy hook (safe).
pub(crate) fn dispatch_trap(info: &TrapInfo) -> TrapAction {
    let raw = TRAP_HOOK.load(Ordering::Acquire);
    if raw == 0 {
        return default_trap_hook(info);
    }
    // SAFETY: `raw` is non-zero here, so it was produced by `set_trap_hook`
    // from a valid `fn(&TrapInfo) -> TrapAction` via `hook as usize`. A function
    // pointer and `usize` are both pointer-sized; this transmute is the exact
    // inverse of that cast.
    let hook: fn(&TrapInfo) -> TrapAction =
        unsafe { core::mem::transmute::<usize, fn(&TrapInfo) -> TrapAction>(raw) };
    hook(info)
}

// ===========================================================================
// M2: cooperative tasks + context switch
// ===========================================================================
//
// Saved-context model (callee-saved-on-stack, the classic cooperative switch):
// `yield_to` saves ONLY the callee-saved registers of the outgoing task onto
// the outgoing task's own stack and records the resulting stack pointer in
// that task's slot; resuming a task is "load its saved SP, pop the
// callee-saved set, return". A single `usize` (the saved SP) is therefore the
// whole per-task context. Caller-saved registers need no saving: `yield_to`
// is an ordinary function call, so the compiler already treats them as dead
// across it.
//
// Verified ABI facts (sources re-checked for M2 — do NOT change the register
// sets or frame layouts without re-reading them):
//  * x86-64 System V psABI (AMD64 ABI 1.0 draft, 2025-03-12, §3.2.1 + Fig 3.4
//    "Register Usage"): "Registers %rbp, %rbx and %r12 through %r15 'belong'
//    to the calling function and the called function is required to preserve
//    their values" → callee-saved GPRs = {rbx, rbp, r12, r13, r14, r15}
//    (+ rsp itself). §3.2.2 "The Stack Frame": at function entry "the value of
//    (%rsp + 8) is a multiple of 16", i.e. RSP % 16 == 8 right after `call`.
//  * AAPCS64 (ARM-software/abi-aa, aapcs64.rst, 2025Q4, §6.1.1 "General-purpose
//    registers"): "r19…r28 | Callee-saved registers" and "Registers r19-r29
//    and SP are Callee-saved"; r29 = FP, r30 = LR (the resume address rides in
//    LR; `ret` branches to it). §6.4.5.1 "Universal stack constraints":
//    "SP mod 16 = 0. The stack must be quad-word aligned."
//  * Initial-frame fabrication technique: OSDev wiki, "Brendan's Multi-tasking
//    Tutorial" (Step 1/2): "put values on the new kernel stack to match the
//    values that your switch_to_task(task) function expects to pop off the
//    stack after switching to the task" — i.e. a fake callee-saved frame whose
//    return address / LR is the task's entry, so the FIRST switch into the
//    task "returns" into `entry`.
//
// No FP/SIMD state is switched: both TABOS targets are soft-float target
// specs, so v8-v15 (AAPCS64) and the SSE/x87 state (psABI) cannot hold live
// values across the switch.

/// Number of task slots tb-hal tracks, INCLUDING slot 0, which is permanently
/// reserved for the bootstrap context (the stack `_start` set up and
/// `rust_main` runs on). M2 needs three (bootstrap + the two ping-pong tasks);
/// eight leaves headroom without needing a heap.
const MAX_TASKS: usize = 8;

/// Per-slot saved stack pointer — the WHOLE saved context of a suspended task
/// under the callee-saved-on-stack model. `0` means "no saved context" (slot
/// never created, or its task is currently running so its slot is stale).
/// `AtomicUsize` because tb-hal is `no_std` with no locks; M2 is single-core
/// cooperative, so the atomics are for safe interior mutability, not racing.
static TASK_SP: [AtomicUsize; MAX_TASKS] = [const { AtomicUsize::new(0) }; MAX_TASKS];

/// Slot index of the task currently executing on this (single) core.
/// `yield_to` updates it right before the raw switch, so a task that is
/// resumed always observes itself as current.
static CURRENT_TASK: AtomicUsize = AtomicUsize::new(0);

/// Next free slot in [`TASK_SP`]; slot 0 is the bootstrap context.
static NEXT_TASK_SLOT: AtomicUsize = AtomicUsize::new(1);

/// Smallest stack [`task_create`] accepts, in `usize` words. The fabricated
/// initial frame needs at most 13 words (aarch64: 12-register stp/ldp frame +
/// 16-byte re-alignment of the top); 64 words also gives the entry a little
/// room before it overflows. Real guard pages arrive with the MMU milestone.
const MIN_STACK_WORDS: usize = 64;

/// An opaque handle to a cooperative kernel task: the slot index into
/// tb-hal's internal saved-SP table. `Copy` so it can be passed around freely;
/// convertible to/from a raw `usize` (see [`Task::raw`]) so the
/// `forbid(unsafe_code)` kernel can stash handles in `AtomicUsize` statics.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct Task(usize);

impl Task {
    /// The raw slot index of this handle, for stashing in an `AtomicUsize`
    /// (cross-task handle passing in safe kernel code goes through statics).
    pub fn raw(self) -> usize {
        self.0
    }

    /// Rebuild a handle from a value previously obtained via [`Task::raw`].
    ///
    /// Safe: a fabricated/invalid index cannot cause memory unsafety — it is
    /// rejected fail-closed by [`yield_to`] (bounds check + "has this slot a
    /// saved context" check), which reports over serial and halts.
    pub fn from_raw(raw: usize) -> Self {
        Task(raw)
    }
}

/// Handle of the task currently executing (slot 0 — the bootstrap context —
/// until the first [`yield_to`] after [`task_create`]).
pub fn current_task() -> Task {
    Task(CURRENT_TASK.load(Ordering::Relaxed))
}

/// Fail-closed termination for misuse of the M2 task API: report the reason
/// over serial (best-effort) and park the core. Never returns.
fn task_api_fatal(msg: &str) -> ! {
    serial_write_str("tb-hal: task: ");
    serial_write_str(msg);
    serial_write_byte(b'\n');
    halt()
}

/// Create a cooperative task that will start executing `entry` the first time
/// somebody [`yield_to`]s it.
///
/// `stack` is caller-provided `'static` memory (the kernel owns its static
/// stack arrays — see [`TaskStack`]; tb-hal does NOT allocate). The arch
/// backend fabricates the INITIAL context frame at the 16-byte-aligned-down
/// top of `stack` — a fake callee-saved frame whose return address (x86_64) /
/// LR slot (aarch64) is `entry` and whose other slots are zero — so the first
/// switch into the task "returns" into `entry` with an ABI-conformant stack
/// (x86_64: RSP % 16 == 8 as after `call`, psABI §3.2.2; aarch64:
/// SP % 16 == 0, AAPCS64 §6.4.5.1).
///
/// `entry` must never return: there is no caller frame beneath it. End it in
/// `halt()` or park it by never yielding back. Fatal (reports + halts) if the
/// stack is too small or all task slots are used.
pub fn task_create(stack: &'static mut [usize], entry: fn()) -> Task {
    if stack.len() < MIN_STACK_WORDS {
        task_api_fatal("task_create: stack too small");
    }
    let slot = NEXT_TASK_SLOT.fetch_add(1, Ordering::Relaxed);
    if slot >= MAX_TASKS {
        task_api_fatal("task_create: too many tasks");
    }
    let sp = arch::task_stack_init(stack, entry);
    TASK_SP[slot].store(sp, Ordering::Release);
    Task(slot)
}

/// Cooperatively switch from the current context to `next`.
///
/// Saves the callee-saved registers + SP of the CURRENT task (on its own
/// stack), records the resulting SP in the current task's slot, then loads
/// `next`'s saved SP, restores its callee-saved registers and returns into it.
/// When somebody later yields back, this function simply returns to its
/// caller, all callee-saved state intact (psABI §3.2.1 / AAPCS64 §6.1.1).
///
/// M2 keeps scheduling explicit/manual: there is no run queue; the caller says
/// exactly which task runs next. Yielding to the current task is a no-op.
/// An invalid handle (out of range, or a slot with no saved context) is fatal:
/// reported over serial, then halt — never a wild jump.
pub fn yield_to(next: Task) {
    if next.0 >= MAX_TASKS {
        task_api_fatal("yield_to: invalid task handle");
    }
    let prev = CURRENT_TASK.load(Ordering::Relaxed);
    if prev == next.0 {
        return; // self-yield: nothing to switch
    }
    let next_sp = TASK_SP[next.0].load(Ordering::Acquire);
    if next_sp == 0 {
        task_api_fatal("yield_to: target has no saved context");
    }
    CURRENT_TASK.store(next.0, Ordering::Relaxed);
    // SAFETY: `next_sp` was produced either by `arch::task_stack_init` over a
    // caller-provided exclusive `&'static mut` stack (fabricated initial
    // frame) or by a previous `ctx_switch` save of a then-live task; both
    // leave a well-formed callee-saved frame at that SP. `TASK_SP[prev]
    // .as_ptr()` points into a `'static` atomic, valid for the single word
    // `ctx_switch` stores. Single core + cooperative switching: no other
    // context can touch either slot while the switch runs.
    unsafe { arch::ctx_switch(TASK_SP[prev].as_ptr(), next_sp) }
}

/// A statically-allocatable, 16-byte-aligned kernel task stack of `WORDS`
/// `usize` words, takeable exactly once as `&'static mut [usize]`.
///
/// Exists so the `#![forbid(unsafe_code)]` kernel crate can OWN its static
/// stack arrays (tb-hal allocates nothing) and still produce the unique
/// `&'static mut` that [`task_create`] requires — safe code cannot otherwise
/// mint a mutable reference into a `static`. The atomic one-shot gate makes
/// aliased handouts impossible; a second [`TaskStack::take`] is fatal
/// (reported over serial, then halt).
#[repr(C, align(16))]
pub struct TaskStack<const WORDS: usize> {
    // First field at offset 0 inherits the struct's 16-byte alignment — both
    // ABIs demand a 16-aligned stack (psABI §3.2.2; AAPCS64 §6.4.5.1
    // "SP mod 16 = 0"), and the arch frame builders keep it that way.
    mem: UnsafeCell<[usize; WORDS]>,
    // One-shot gate, flipped by the first `take()`.
    taken: AtomicBool,
}

// SAFETY: the ONLY route to the inner array is `take()`, whose atomic
// swap-once gate hands out at most one `&'static mut` ever (a racing second
// caller loses the swap and halts), so shared references to the cell are never
// used to alias the interior data.
unsafe impl<const WORDS: usize> Sync for TaskStack<WORDS> {}

impl<const WORDS: usize> TaskStack<WORDS> {
    /// A new zeroed stack; `const`, so it can initialise a kernel `static`.
    pub const fn new() -> Self {
        TaskStack {
            mem: UnsafeCell::new([0; WORDS]),
            taken: AtomicBool::new(false),
        }
    }

    /// Hand out the stack as `&'static mut [usize]` — exactly once.
    ///
    /// A second call on the same static is a fatal API misuse: it reports over
    /// serial and halts (fail-closed; it can never mint a second aliasing
    /// `&mut`).
    pub fn take(&'static self) -> &'static mut [usize] {
        if self.taken.swap(true, Ordering::AcqRel) {
            task_api_fatal("TaskStack::take: taken twice");
        }
        // SAFETY: the swap above guarantees this body runs at most once per
        // static instance, so the `&mut` minted here is unique for `'static`;
        // `UnsafeCell` makes mutating the interior of an immutable `static`
        // well-defined.
        let array: &'static mut [usize; WORDS] = unsafe { &mut *self.mem.get() };
        &mut array[..]
    }
}

//! Architecture dispatch for `tb-hal`.
//!
//! `lib.rs` calls the arch primitives through this module; they are re-exported
//! here from whichever per-arch submodule matches the build target. The
//! submodules (`arch/x86_64/{mod,boot,serial,gdt,idt,trap,sched}.rs`,
//! `arch/aarch64/{mod,boot,serial,trap,vectors,sched}.rs`) contain ALL of the
//! crate's `unsafe` + assembly and are emitted separately; THIS file only wires
//! them up.
//!
//! INTERNAL CONTRACT each `arch/<arch>/mod.rs` must satisfy (see BUILD.md):
//!   * `pub fn serial_init();`
//!   * `pub fn serial_write_byte(b: u8);`
//!   * `pub fn halt() -> !;`
//!   * `pub fn install_traps();`   (M1 — load GDT/TSS/IDT or set VBAR_EL1)
//!   * `pub fn breakpoint();`      (M1 — int3 / brk #0)
//!   * `pub fn task_stack_init(stack: &mut [usize], entry: fn()) -> usize;`
//!     (M2 — fabricate the INITIAL context frame at the 16-aligned-down top of
//!      `stack` so the first switch into the task "returns" into `entry`,
//!      returning the initial saved SP. x86_64: `[entry]` at a 16-aligned slot
//!      as the return address + 6 zeroed callee-saved slots {rbx, rbp,
//!      r12..r15} below it, so `entry` observes RSP % 16 == 8 — the psABI
//!      §3.2.2 post-`call` state. aarch64: a 96-byte stp/ldp frame holding
//!      {x19..x28, x29(FP), x30(LR)} with x30 = entry and the rest zeroed; SP
//!      stays 16-aligned per AAPCS64 §6.4.5.1.)
//!   * `pub unsafe extern "C" fn ctx_switch(prev_sp_save: *mut usize,
//!      next_sp: usize);`
//!     (M2 — naked cooperative switch: push/stp the CALLEE-SAVED set of the
//!      current task onto its own stack — x86-64 SysV psABI §3.2.1 {rbx, rbp,
//!      r12, r13, r14, r15}; AAPCS64 §6.1.1 {x19..x28, x29, x30} — store the
//!      resulting SP to `*prev_sp_save`, load `next_sp` into SP, pop/ldp the
//!      same set and return into the next task. The resume address travels as
//!      the on-stack return address (x86_64) / in x30+`ret` (aarch64).)
//!   * plus the boot entry (`_start`, via `global_asm!`) and the
//!     XEN_ELFNOTE_PHYS32_ENTRY note (x86_64 only), which the linker keeps.

#[cfg(target_arch = "x86_64")]
pub mod x86_64;
#[cfg(target_arch = "x86_64")]
pub use self::x86_64::{
    breakpoint, ctx_switch, halt, install_traps, serial_init, serial_write_byte, task_stack_init,
};

#[cfg(target_arch = "aarch64")]
pub mod aarch64;
#[cfg(target_arch = "aarch64")]
pub use self::aarch64::{
    breakpoint, ctx_switch, halt, install_traps, serial_init, serial_write_byte, task_stack_init,
};

#[cfg(not(any(target_arch = "x86_64", target_arch = "aarch64")))]
compile_error!(
    "tb-hal supports only x86_64 and aarch64 (the two Firecracker-class arches); \
     build with --target targets/x86_64-tabos-none.json or \
     targets/aarch64-tabos-none.json"
);

//! TABOS kernel entry shim (M2: cooperative context switch).
//!
//! Framekernel rule: the kernel crate is otherwise safe Rust. THIS file is the
//! single permitted exception. It contains no `unsafe {}` blocks; the only
//! reason crate-level `forbid(unsafe_code)` is not applied here is that
//! `#[unsafe(no_mangle)]` is itself an *unsafe attribute* (it tells the linker
//! to expose `rust_main` un-mangled for tb-hal's `_start` to `call`/`b` into),
//! and the `unsafe_code` lint flags it. All real unsafe + assembly is confined
//! to tb-hal (KERNEL-FOUNDATION-SPEC.md §1).
//!
//! M2 proves the cooperative context switch: two kernel tasks (A and B) on
//! kernel-owned static stacks voluntarily `yield_to` each other for
//! `ROUND_TRIPS` strict A,B,A,B round-trips. tb-hal switches only the ABI
//! callee-saved registers + SP (x86-64 SysV psABI §3.2.1: {rbx, rbp,
//! r12..r15}; AAPCS64 §6.1.1: {x19..x28, x29, x30}), so each task carries
//! locals ACROSS every yield as a REGISTER-INTEGRITY CANARY: if the switch
//! corrupted a callee-saved register (or the saved SP), the loop counters,
//! accumulators or rotating patterns diverge and the test prints
//! "M2: FAIL <why>". On success it prints the DoD marker
//! "M2: context-switch OK". The M0 serial hello and the M1 breakpoint
//! round-trip are kept verbatim ahead of it, so one boot still proves all
//! three milestones.

#![no_std]
#![no_main]

use core::hint::black_box;
use core::panic::PanicInfo;
use core::sync::atomic::{AtomicBool, AtomicUsize, Ordering};
use tb_hal::{Task, TaskStack, TrapAction, TrapInfo, TrapKind};

/// Ping-pong round-trips (A→B→A counts as one). DoD asks for >= 1000.
const ROUND_TRIPS: usize = 1000;

/// `TURN` value meaning "task A must run this half-round".
const TURN_A: usize = 0;
/// `TURN` value meaning "task B must run this half-round".
const TURN_B: usize = 1;

/// Initial value of task A's rotating-pattern canary (arbitrary, asymmetric).
const PAT_A_INIT: usize = 0xA5A5_5A5A_DEAD_BEEF;
/// Initial value of task B's rotating-pattern canary (different from A's).
const PAT_B_INIT: usize = 0x0F0F_F0F0_CAFE_F00D;

// --- M2 scheduler bookkeeping (all in THIS forbid-class crate, all safe) ----
// Stacks are kernel-OWNED statics (tb-hal allocates nothing); `TaskStack` is
// tb-hal's one-shot cell that mints the `&'static mut [usize]` safe code
// cannot otherwise produce. 4096 words = 32 KiB per task.

/// Task A's stack: 4096 usize words (32 KiB), 16-byte aligned.
static STACK_A: TaskStack<4096> = TaskStack::new();
/// Task B's stack: 4096 usize words (32 KiB), 16-byte aligned.
static STACK_B: TaskStack<4096> = TaskStack::new();

/// Task A's handle as `Task::raw()`, stashed so task B can yield back to A.
static TASK_A_RAW: AtomicUsize = AtomicUsize::new(usize::MAX);
/// Task B's handle as `Task::raw()`, stashed so task A can yield to B.
static TASK_B_RAW: AtomicUsize = AtomicUsize::new(usize::MAX);

/// Whose half-round it is: the strict-alternation flag (TURN_A / TURN_B).
/// Each side asserts it on entry and flips it before yielding.
static TURN: AtomicUsize = AtomicUsize::new(TURN_A);

/// Shared increment counter: A sees it == 2*i at round i, B sees == 2*j + 1;
/// any double-run or skipped turn breaks the sequence immediately.
static COUNTER: AtomicUsize = AtomicUsize::new(0);

/// Set by task B after it audited its own canaries on its final round;
/// task A requires it before declaring the milestone passed.
static B_VERIFIED: AtomicBool = AtomicBool::new(false);

/// Boot entry. tb-hal's per-arch `_start` jumps here after it has set up a
/// stack, zeroed `.bss`, and placed the boot-info pointer in arg0 (SysV `rdi`
/// on x86_64 = `hvm_start_info` phys addr; AAPCS64 `x0` on aarch64 = FDT blob).
#[unsafe(no_mangle)]
pub extern "C" fn rust_main(boot_info: usize) -> ! {
    // M0..M2 ignore boot_info; a later milestone parses hvm_start_info / FDT.
    let _ = boot_info;

    // --- M0 proof (kept verbatim): serial first-light ----------------------
    tb_hal::serial_init();
    tb_hal::serial_write_str("hello from rust_main\n");

    // --- M1 proof (kept): install traps, take a breakpoint, resume ---------
    tb_hal::install_traps();
    tb_hal::set_trap_hook(trap_hook);
    tb_hal::serial_write_str("trap-test: triggering breakpoint\n");
    tb_hal::breakpoint(); // int3 (x86_64) / brk #0 (aarch64); hook -> Resume
    tb_hal::serial_write_str("trap-test: resumed past breakpoint\n");
    tb_hal::serial_write_str("M1: traps OK\n");

    // --- M2: cooperative context-switch ping-pong ---------------------------
    // Create both tasks on kernel-owned static stacks, publish their handles
    // for cross-task use (handles travel as raw usizes through atomics — the
    // only `'static` channel available to forbid(unsafe_code) code), then hand
    // the CPU to task A. This bootstrap context is never scheduled again.
    tb_hal::serial_write_str("ctx-test: starting ping-pong\n");
    let task_a = tb_hal::task_create(STACK_A.take(), task_a_main);
    let task_b = tb_hal::task_create(STACK_B.take(), task_b_main);
    TASK_A_RAW.store(task_a.raw(), Ordering::Release);
    TASK_B_RAW.store(task_b.raw(), Ordering::Release);
    tb_hal::yield_to(task_a);

    // Task A ends the run with halt() on both verdicts; control must never
    // return to the bootstrap context.
    fail("bootstrap context resumed unexpectedly")
}

/// Task A ("ping"): drives `ROUND_TRIPS` strict A,B,A,B round-trips against
/// task B, then renders the M2 verdict.
///
/// REGISTER-INTEGRITY CANARY: `i`, `a_loops`, `a_sum` and `a_pat` stay live
/// ACROSS every `yield_to`. Caller-saved registers are dead at the call, so
/// the compiler holds these in callee-saved registers (or spills them to this
/// task's OWN stack — equally covered, since the switch must preserve the
/// saved SP). `black_box` keeps the optimizer from folding the checks away.
fn task_a_main() {
    let task_b = Task::from_raw(TASK_B_RAW.load(Ordering::Acquire));

    let mut a_loops: usize = 0; // canary 1: monotonic loop count
    let mut a_sum: usize = 0; // canary 2: accumulator over the index
    let mut a_pat: usize = PAT_A_INIT; // canary 3: rotating bit pattern

    let mut i: usize = 0;
    while i < ROUND_TRIPS {
        // Strict alternation: it must be A's turn, with the shared counter
        // exactly at 2*i (A and B each incremented it i times so far).
        if TURN.load(Ordering::Acquire) != TURN_A {
            fail("A: turn flag not A at round start");
        }
        let c = COUNTER.load(Ordering::Acquire);
        if c != 2 * i {
            fail("A: shared counter out of sequence");
        }
        // Canary: the local loop count must track the loop index exactly.
        if black_box(a_loops) != i {
            fail("A: local loop canary corrupted");
        }
        COUNTER.store(c + 1, Ordering::Release);
        a_loops = black_box(a_loops) + 1;
        a_sum = black_box(a_sum).wrapping_add(i);
        a_pat = black_box(a_pat).rotate_left(1);
        TURN.store(TURN_B, Ordering::Release);

        tb_hal::yield_to(task_b); // <-- the cooperative switch under test

        if TURN.load(Ordering::Acquire) != TURN_A {
            fail("A: alternation broken after resume");
        }
        i += 1;
    }

    // Final canary audit: recompute the expected values with the same ops in
    // a yield-free loop and compare against what survived 2*ROUND_TRIPS
    // context switches.
    let mut want_sum: usize = 0;
    let mut want_pat: usize = PAT_A_INIT;
    let mut k: usize = 0;
    while k < ROUND_TRIPS {
        want_sum = black_box(want_sum).wrapping_add(k);
        want_pat = black_box(want_pat).rotate_left(1);
        k += 1;
    }
    if black_box(a_loops) != ROUND_TRIPS {
        fail("A: final loop count wrong");
    }
    if black_box(a_sum) != want_sum {
        fail("A: final sum canary wrong");
    }
    if black_box(a_pat) != want_pat {
        fail("A: final pattern canary wrong");
    }
    if COUNTER.load(Ordering::Acquire) != 2 * ROUND_TRIPS {
        fail("A: final shared counter wrong");
    }
    if !B_VERIFIED.load(Ordering::Acquire) {
        fail("A: task B never reported success");
    }

    tb_hal::serial_write_str("M2: context-switch OK\n"); // <-- the M2 DoD marker
    tb_hal::halt()
}

/// Task B ("pong"): mirror half of the ping-pong, with its own canary locals
/// live across every yield. Audits its canaries on the FINAL round before the
/// last yield (A never resumes it afterwards) and publishes the verdict via
/// `B_VERIFIED`.
fn task_b_main() {
    let task_a = Task::from_raw(TASK_A_RAW.load(Ordering::Acquire));

    let mut b_loops: usize = 0; // canary 1: monotonic loop count
    let mut b_sum: usize = 0; // canary 2: accumulator over the index
    let mut b_pat: usize = PAT_B_INIT; // canary 3: rotating bit pattern

    let mut j: usize = 0;
    while j < ROUND_TRIPS {
        if TURN.load(Ordering::Acquire) != TURN_B {
            fail("B: turn flag not B at round start");
        }
        let c = COUNTER.load(Ordering::Acquire);
        if c != 2 * j + 1 {
            fail("B: shared counter out of sequence");
        }
        if black_box(b_loops) != j {
            fail("B: local loop canary corrupted");
        }
        COUNTER.store(c + 1, Ordering::Release);
        b_loops = black_box(b_loops) + 1;
        b_sum = black_box(b_sum).wrapping_add(j);
        b_pat = black_box(b_pat).rotate_left(1);
        j += 1;

        if j == ROUND_TRIPS {
            // Last round: audit B's canaries NOW — after the yield below this
            // task is parked forever, so this is its only chance to report.
            let mut want_sum: usize = 0;
            let mut want_pat: usize = PAT_B_INIT;
            let mut k: usize = 0;
            while k < ROUND_TRIPS {
                want_sum = black_box(want_sum).wrapping_add(k);
                want_pat = black_box(want_pat).rotate_left(1);
                k += 1;
            }
            if black_box(b_loops) != ROUND_TRIPS {
                fail("B: final loop count wrong");
            }
            if black_box(b_sum) != want_sum {
                fail("B: final sum canary wrong");
            }
            if black_box(b_pat) != want_pat {
                fail("B: final pattern canary wrong");
            }
            B_VERIFIED.store(true, Ordering::Release);
        }

        TURN.store(TURN_A, Ordering::Release);
        tb_hal::yield_to(task_a); // <-- the cooperative switch under test
    }

    // Only reachable if A (wrongly) resumes B after its last round.
    fail("B: resumed after completing all rounds")
}

/// Emit the M2 failure verdict ("M2: FAIL <why>") over serial and park the
/// core. Never returns; the run scripts then miss the OK marker and fail.
fn fail(why: &str) -> ! {
    tb_hal::serial_write_str("M2: FAIL ");
    tb_hal::serial_write_str(why);
    tb_hal::serial_write_byte(b'\n');
    tb_hal::halt()
}

/// Safe trap-dispatch policy hook (kept from M1: policy lives in this
/// `forbid(unsafe_code)`-class crate, not in tb-hal's raw entry asm).
///
/// tb-hal's per-arch `extern "C"` handler builds this [`TrapInfo`] from the raw
/// `TrapFrame` and calls us. A [`TrapKind::Breakpoint`] is resumed (prove the
/// round-trip); any other trap is reported and the core is halted.
fn trap_hook(info: &TrapInfo) -> TrapAction {
    match info.kind {
        TrapKind::Breakpoint => {
            tb_hal::serial_write_str("trap: breakpoint, resuming\n");
            TrapAction::Resume
        }
        _ => {
            // Fatal fault: report the cause/faulting-address/pc, then halt.
            tb_hal::serial_write_str("trap: fatal fault, halting\n");
            tb_hal::serial_write_str("  cause=");
            write_hex_u64(info.cause);
            tb_hal::serial_write_str(" fault_addr=");
            write_hex_u64(info.fault_addr);
            tb_hal::serial_write_str(" pc=");
            write_hex_u64(info.pc);
            tb_hal::serial_write_byte(b'\n');
            TrapAction::Halt
        }
    }
}

/// Write a `u64` as a fixed-width 16-digit `0x…` hex string over serial.
///
/// Pure safe Rust (no `core::fmt`, no allocation): just shifts nibbles out of
/// the value and emits ASCII via the tb-hal byte writer.
fn write_hex_u64(value: u64) {
    tb_hal::serial_write_str("0x");
    let mut shift: i32 = 60;
    while shift >= 0 {
        let nibble = ((value >> shift) & 0xf) as u8;
        let c = if nibble < 10 {
            b'0' + nibble
        } else {
            b'a' + (nibble - 10)
        };
        tb_hal::serial_write_byte(c);
        shift -= 4;
    }
}

/// Panic handler: best-effort marker over serial, then halt forever.
#[panic_handler]
fn panic(_info: &PanicInfo) -> ! {
    tb_hal::serial_write_str("panic\n");
    tb_hal::halt()
}
